#!/usr/bin/env node
// Execute the duplicate-merge plan generated by find-duplicates.js.
//
// For each pair (survivor = oldest id, drop = newer id):
//   1. Patch survivor with fields from drop where drop wins (per _logic.js).
//   2. Transfer relations: PlaceSource, Visit, Favorite, Review, PlaceStyle,
//      Faq — deduped where the model has a unique constraint.
//   3. Move hero image file if survivor's heroImageUrl now points at drop's id.
//   4. Delete drop row.
// All wrapped in a single Prisma transaction per pair — fully applies or
// rolls back. No partial state on failure.
//
// Flagged pairs (different phones / gpids) are SKIPPED by default — they
// need human review. Pass --include-flagged to also process them (rare).
//
// Usage:
//   node scripts/dedup/merge-duplicates.js [--dry-run] [--limit N] [--include-flagged] [--pair S:D]
//
//   --dry-run       — print plan, no writes
//   --limit N       — process at most N pairs (after sort)
//   --pair 324:1622 — process only this single pair (S=survivor, D=drop)
//
// All actions logged to data/reports/dedup-merge-{timestamp}.log so we have
// a permanent record of every UPDATE/DELETE for forensics.

const fs = require('fs');
const path = require('path');
const { prisma, ROOT, PATHS } = require('../lib/bootstrap');
const { normalizePlaceName } = require(path.join(ROOT, 'src/services/normalize-place-name'));
const { buildPlan, haversineM } = require('./_logic');

const args = process.argv.slice(2);
const DRY_RUN = args.includes('--dry-run');
const INCLUDE_FLAGGED = args.includes('--include-flagged');
const LIMIT = (() => {
    const i = args.indexOf('--limit');
    if (i === -1) return null;
    const n = parseInt(args[i + 1], 10);
    return Number.isFinite(n) ? n : null;
})();
const PAIR_FILTER = (() => {
    const i = args.indexOf('--pair');
    if (i === -1) return null;
    const m = args[i + 1] && args[i + 1].match(/^(\d+):(\d+)$/);
    return m ? { s: parseInt(m[1], 10), d: parseInt(m[2], 10) } : null;
})();

const COORD_MATCH_M = 100;

const TS = new Date().toISOString().replace(/[:.]/g, '-');
const LOG_PATH = path.join(PATHS.reports, `dedup-merge-${TS}.log`);
const logStream = DRY_RUN ? null : fs.createWriteStream(LOG_PATH, { flags: 'a' });
function log(msg) {
    console.log(msg);
    if (logStream) logStream.write(msg + '\n');
}

// Detect existing hero image file for a place. Returns path + ext or null.
function findHeroFile(placeId) {
    const dir = path.join(ROOT, 'public', 'uploads', 'places');
    for (const ext of ['jpg', 'jpeg', 'png', 'webp', 'gif']) {
        const p = path.join(dir, `${placeId}.${ext}`);
        if (fs.existsSync(p)) return { path: p, ext };
    }
    return null;
}

async function loadPairs() {
    const places = await prisma.place.findMany({
        where: { status: 'active' },
        include: {
            sources: { select: { id: true, source: true, rank: true } },
            visits: { select: { id: true, userId: true } },
            favorites: { select: { id: true, userId: true } },
            reviews: { select: { id: true } },
            styles: { select: { styleId: true } },
            faqs: { select: { id: true } },
        },
    });
    // Same name-bucket + same-gpid candidate logic as find-duplicates.js.
    const buckets = new Map();
    const byGpid = new Map();
    for (const p of places) {
        if (!p.lat || !p.lng) continue;
        const k = (p.country || '') + '|' + normalizePlaceName(p.name);
        if (!buckets.has(k)) buckets.set(k, []);
        buckets.get(k).push(p);
        if (p.googlePlaceId) {
            if (!byGpid.has(p.googlePlaceId)) byGpid.set(p.googlePlaceId, []);
            byGpid.get(p.googlePlaceId).push(p);
        }
    }
    const seen = new Set();
    const pairs = [];
    const addPair = (a, b, dist) => {
        const lo = Math.min(a.id, b.id), hi = Math.max(a.id, b.id);
        const k = lo + ':' + hi;
        if (seen.has(k)) return;
        seen.add(k);
        pairs.push({ survivor: a.id < b.id ? a : b, drop: a.id < b.id ? b : a, distM: dist });
    };
    for (const arr of buckets.values()) {
        if (arr.length < 2) continue;
        for (let i = 0; i < arr.length; i++) for (let j = i + 1; j < arr.length; j++) {
            const a = arr[i], b = arr[j];
            const d = haversineM(Number(a.lat), Number(a.lng), Number(b.lat), Number(b.lng));
            const sameGpid = a.googlePlaceId && b.googlePlaceId && a.googlePlaceId === b.googlePlaceId;
            if (sameGpid || d <= COORD_MATCH_M) addPair(a, b, Math.round(d));
        }
    }
    for (const arr of byGpid.values()) {
        if (arr.length < 2) continue;
        for (let i = 0; i < arr.length; i++) for (let j = i + 1; j < arr.length; j++) {
            const a = arr[i], b = arr[j];
            const d = haversineM(Number(a.lat), Number(a.lng), Number(b.lat), Number(b.lng));
            addPair(a, b, Math.round(d));
        }
    }
    return pairs;
}

// Single-transaction merge for one pair. Returns a summary object.
async function mergePair(pair, plan) {
    const { survivor: s, drop: d, distM } = pair;
    const { wins } = plan;

    // Build the UPDATE payload from wins. Decimal columns (lat/lng) must be
    // passed as strings/Decimals — Prisma's findMany returns Decimal objects.
    const updateData = {};
    for (const w of wins) {
        updateData[w.field] = w.newValue;
    }

    // Hero image file handling. If we just patched survivor's heroImageUrl
    // to drop's `/uploads/places/{drop.id}.{ext}`, copy the file to the
    // survivor's id path AND rewrite the URL.
    let heroFileMoved = null;
    const newHero = updateData.heroImageUrl ?? s.heroImageUrl;
    if (typeof newHero === 'string' && newHero.startsWith('/uploads/places/')) {
        const m = newHero.match(/^\/uploads\/places\/(\d+)\.([a-z0-9]+)$/i);
        if (m && parseInt(m[1], 10) === d.id) {
            const srcFile = path.join(ROOT, 'public', 'uploads', 'places', `${d.id}.${m[2]}`);
            const dstFile = path.join(ROOT, 'public', 'uploads', 'places', `${s.id}.${m[2]}`);
            heroFileMoved = { src: srcFile, dst: dstFile, ext: m[2] };
            updateData.heroImageUrl = `/uploads/places/${s.id}.${m[2]}`;
        }
    }

    if (DRY_RUN) {
        log(`[dry-run] merge ${d.id} → ${s.id}  "${d.name}" → "${s.name}" (${s.city}, ${distM}m)`);
        log(`  patch fields: ${wins.map((w) => w.field).join(', ') || '(none)'}`);
        if (heroFileMoved) log(`  hero copy: ${path.relative(ROOT, heroFileMoved.src)} → ${path.relative(ROOT, heroFileMoved.dst)}`);
        return { mode: 'dry-run' };
    }

    // Pre-compute relation transfers OUTSIDE the transaction to keep the
    // transaction snappy and avoid timeouts on rows with lots of visits/etc.
    const svSourceNames = new Set(s.sources.map((x) => x.source));
    const sourcesToTransfer = d.sources.filter((x) => !svSourceNames.has(x.source));
    const sourcesToDelete = d.sources.filter((x) => svSourceNames.has(x.source));

    const svVisitUsers = new Set(s.visits.map((x) => x.userId));
    const visitsToTransfer = d.visits.filter((x) => !svVisitUsers.has(x.userId));
    const visitsToDelete = d.visits.filter((x) => svVisitUsers.has(x.userId));

    const svFavUsers = new Set(s.favorites.map((x) => x.userId));
    const favsToTransfer = d.favorites.filter((x) => !svFavUsers.has(x.userId));
    const favsToDelete = d.favorites.filter((x) => svFavUsers.has(x.userId));

    const svStyleIds = new Set(s.styles.map((x) => x.styleId));
    const stylesToTransfer = d.styles.filter((x) => !svStyleIds.has(x.styleId));
    const stylesToDelete = d.styles.filter((x) => svStyleIds.has(x.styleId));

    const result = await prisma.$transaction(async (tx) => {
        // 0. Pre-clear unique columns on drop that survivor will inherit.
        //    Without this, the survivor UPDATE collides with the still-extant
        //    drop on `googlePlaceId` (UNIQUE) before we get to the DELETE.
        //    Slug isn't transferred (survivor keeps its own), so only gpid.
        if (updateData.googlePlaceId && d.googlePlaceId) {
            await tx.place.update({ where: { id: d.id }, data: { googlePlaceId: null } });
        }
        // 1. Patch survivor.
        if (Object.keys(updateData).length) {
            await tx.place.update({ where: { id: s.id }, data: updateData });
        }
        // 2. Transfer PlaceSource (UPDATE placeId, dedupe by source).
        for (const r of sourcesToTransfer) {
            await tx.placeSource.update({ where: { id: r.id }, data: { placeId: s.id } });
        }
        for (const r of sourcesToDelete) {
            await tx.placeSource.delete({ where: { id: r.id } });
        }
        // 3. Visits (unique on [userId, placeId]).
        for (const r of visitsToTransfer) {
            await tx.visit.update({ where: { id: r.id }, data: { placeId: s.id } });
        }
        for (const r of visitsToDelete) {
            await tx.visit.delete({ where: { id: r.id } });
        }
        // 4. Favorites (likely also unique on [userId, placeId]).
        for (const r of favsToTransfer) {
            await tx.favorite.update({ where: { id: r.id }, data: { placeId: s.id } });
        }
        for (const r of favsToDelete) {
            await tx.favorite.delete({ where: { id: r.id } });
        }
        // 5. Reviews — transfer all (user content, never lose).
        if (d.reviews.length) {
            await tx.review.updateMany({ where: { placeId: d.id }, data: { placeId: s.id } });
        }
        // 6. PlaceStyle (composite PK [placeId, styleId]).
        for (const r of stylesToTransfer) {
            await tx.placeStyle.update({ where: { placeId_styleId: { placeId: d.id, styleId: r.styleId } }, data: { placeId: s.id } });
        }
        for (const r of stylesToDelete) {
            await tx.placeStyle.delete({ where: { placeId_styleId: { placeId: d.id, styleId: r.styleId } } });
        }
        // 7. Faqs — transfer all.
        if (d.faqs.length) {
            await tx.faq.updateMany({ where: { placeId: d.id }, data: { placeId: s.id } });
        }
        // 8. Delete drop. Any remaining cascading FKs (none expected by now)
        //    get deleted with it.
        await tx.place.delete({ where: { id: d.id } });
        return { ok: true };
    }, { timeout: 30000 });

    // 9. Hero image file move — OUTSIDE the transaction (filesystem is not
    //    transactional anyway; do it last so a tx failure doesn't leave a
    //    half-moved file).
    if (heroFileMoved) {
        try {
            fs.copyFileSync(heroFileMoved.src, heroFileMoved.dst);
        } catch (e) {
            log(`  WARN: hero file copy failed: ${e.message}`);
        }
    }
    log(`merged ${d.id} → ${s.id}  fields=${wins.length}  sources=${sourcesToTransfer.length}+${sourcesToDelete.length}d  visits=${visitsToTransfer.length}+${visitsToDelete.length}d  reviews=${d.reviews.length}  styles=${stylesToTransfer.length}+${stylesToDelete.length}d`);
    return result;
}

async function main() {
    log(`[mode] dry-run=${DRY_RUN}  include-flagged=${INCLUDE_FLAGGED}  limit=${LIMIT ?? 'none'}  pair=${PAIR_FILTER ? `${PAIR_FILTER.s}:${PAIR_FILTER.d}` : 'all'}`);

    const allPairs = await loadPairs();
    log(`[load] ${allPairs.length} candidate duplicate pairs`);

    let pairs = allPairs;
    if (PAIR_FILTER) {
        pairs = pairs.filter((p) => p.survivor.id === PAIR_FILTER.s && p.drop.id === PAIR_FILTER.d);
        if (!pairs.length) {
            log(`No pair matching ${PAIR_FILTER.s}:${PAIR_FILTER.d} found. Note: survivor must be the LOWER id.`);
            await prisma.$disconnect();
            return;
        }
    }
    // Build plans, partition by flagged.
    const planned = pairs.map((p) => ({ pair: p, plan: buildPlan(p.survivor, p.drop) }));
    const flagged = planned.filter((x) => x.plan.flags.length > 0);
    let runnable = planned.filter((x) => x.plan.flags.length === 0);
    if (INCLUDE_FLAGGED) runnable = planned;
    log(`[partition] runnable=${runnable.length}  flagged=${flagged.length}  ${INCLUDE_FLAGGED ? '(including flagged)' : '(skipping flagged)'}`);

    if (LIMIT && runnable.length > LIMIT) {
        runnable = runnable.slice(0, LIMIT);
        log(`[limit] processing first ${LIMIT}`);
    }

    let ok = 0, errored = 0;
    for (const { pair, plan } of runnable) {
        try {
            await mergePair(pair, plan);
            ok++;
        } catch (e) {
            errored++;
            log(`ERROR merging ${pair.drop.id} → ${pair.survivor.id}: ${e.message}`);
        }
    }

    log(`[done] merged=${ok}  errored=${errored}  flagged-skipped=${INCLUDE_FLAGGED ? 0 : flagged.length}`);
    if (logStream) {
        log(`[log] full audit → ${path.relative(ROOT, LOG_PATH)}`);
        logStream.end();
    }
    await prisma.$disconnect();
}

main().catch((e) => { console.error(e); process.exit(1); });
